@app.route('/login')
def login():
    if not oidc_config:
        return "OIDC configuration not loaded. Please check server logs.", 500

    authorize_url = oidc_config.get('authorization_endpoint')
    if not authorize_url:
        return "Authorization endpoint not found in OIDC configuration.", 500

    state = base64.urlsafe_b64encode(os.urandom(16)).decode('utf-8')
    nonce = base64.urlsafe_b64encode(os.urandom(16)).decode('utf-8')
    code_verifier, code_challenge = generate_pkce_codes()

    session['oidc_state'] = state
    session['oidc_nonce'] = nonce
    session['oidc_code_verifier'] = code_verifier

    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'scope': SCOPE,
        'state': state,
        'nonce': nonce,
        'code_challenge': code_challenge,
        'code_challenge_method': 'S256',
    }

    auth_request_url = requests.Request('GET', authorize_url, params=params).prepare().url
    return redirect(auth_request_url)

@app.route('/oidc_callback')
def oidc_callback():
    if not oidc_config:
        return "OIDC configuration not loaded. Please check server logs.", 500

    token_endpoint = oidc_config.get('token_endpoint')
    if not token_endpoint:
        return "Token endpoint not found in OIDC configuration.", 500

    if 'error' in request.args:
        error_description = request.args.get('error_description', request.args['error'])
        return f"Authentication failed: {error_description}", 400

    if 'code' not in request.args or 'state' not in request.args:
        return "Missing code or state in callback.", 400

    # Validate state parameter to mitigate CSRF
    if request.args['state'] != session.pop('oidc_state', None):
        return "State mismatch. Possible CSRF attack.", 400

    code = request.args['code']
    code_verifier = session.pop('oidc_code_verifier', None)

    if not code_verifier:
        return "Code verifier missing from session. PKCE flow compromised or session expired.", 400

    token_params = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET,
        'code_verifier': code_verifier,
    }

    try:
        token_response = requests.post(token_endpoint, data=token_params)
        token_response.raise_for_status()
        tokens = token_response.json()

        id_token = tokens.get('id_token')
        access_token = tokens.get('access_token')
        refresh_token = tokens.get('refresh_token') # Optional

        if not id_token:
            return "ID Token not received from OIDC provider.", 500

        user_claims = decode_id_token(id_token)

        if not user_claims:
            return "Failed to decode ID Token.", 500

        # Basic validation for nonce (recommended to implement full validation including signature verification)
        if user_claims.get('nonce') != session.pop('oidc_nonce', None):
            app.logger.warning("Nonce mismatch in ID Token. Potential replay attack.")
            # Depending on security requirements, this might warrant an error or just a warning
            # For a production system, full ID Token validation (signature, issuer, audience, exp, etc.) is crucial.

        # Store relevant user info in session
        session['user_info'] = {
            'sub': user_claims.get('sub'), # Subject identifier
            'name': user_claims.get('name', user_claims.get('preferred_username')),
            'email': user_claims.get('email'),
            'picture': user_claims.get('picture'),
            # Add other claims you need
        }
        session['id_token'] = id_token
        session['access_token'] = access_token
        if refresh_token:
            session['refresh_token'] = refresh_token

        app.logger.info(f"User '{session['user_info'].get('name', user_claims.get('sub'))}' logged in successfully.")
        return redirect(url_for('index'))

    except requests.exceptions.RequestException as e:
        app.logger.error(f"Error exchanging code for tokens: {e}")
        return "Error during token exchange.", 500
    except Exception as e:
        app.logger.error(f"An unexpected error occurred in callback: {e}")
        return "An unexpected error occurred.", 500

@app.route('/logout')
def logout():
    session.pop('user_info', None)
    session.pop('id_token', None)
    session.pop('access_token', None)
    session.pop('refresh_token', None)
    # Clear any other OIDC-related session variables
